CREATE TABLE public.orders_shipment_evidence (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), client_id uuid NOT NULL REFERENCES public.clients(id) ON DELETE CASCADE, shipment_id uuid NOT NULL REFERENCES public.orders_shipments(id) ON DELETE CASCADE, event_type text NOT NULL CHECK (event_type IN ('dispatched', 'delivered')), idempotency_key text NOT NULL, recorded_by uuid REFERENCES public.user_nodes(id) ON DELETE SET NULL, recorded_at timestamptz NOT NULL DEFAULT now(), provider_reference text, CONSTRAINT orders_shipment_evidence_client_key_uniq UNIQUE (client_id, idempotency_key), CONSTRAINT orders_shipment_evidence_shipment_event_uniq UNIQUE (shipment_id, event_type));
CREATE INDEX orders_shipment_evidence_client_shipment_idx ON public.orders_shipment_evidence (client_id, shipment_id, recorded_at DESC);
